function toastManager(){return{toasts:[],nextId:1,addToast(t,e,s="",o=5e3){const a=this.nextId++,i={id:a,type:t,title:e,message:s,show:!0};this.toasts.push(i),o>0&&setTimeout(()=>this.removeToast(a),o)},removeToast(t){const e=this.toasts.findIndex(e=>e.id===t);e>-1&&(this.toasts[e].show=!1,setTimeout(()=>{this.toasts.splice(e,1)},300))}}}function tableSelection(){return{selectedAll:!1,selectedRows:[],get selectedCount(){return this.selectedRows.length},get showBulkActions(){return this.selectedCount>0},toggleAll(){this.selectedAll=!this.selectedAll;document.querySelectorAll(".row-checkbox").forEach(t=>{t.checked=this.selectedAll}),this.updateSelection()},updateSelection(){const t=document.querySelectorAll(".row-checkbox");this.selectedAll=Array.from(t).every(t=>t.checked),this.selectedRows=Array.from(t).filter(t=>t.checked).map(t=>t.value)}}}function calendarWidget(){return{today:new Date,viewDate:new Date,get monthYear(){return this.viewDate.toLocaleString("default",{month:"long",year:"numeric"})},get todayLabel(){return this.today.toLocaleString("default",{month:"long",day:"numeric"})},get daysArray(){const t=this.viewDate.getFullYear(),e=this.viewDate.getMonth(),s=new Date(t,e,1),o=new Date(t,e+1,0).getDate(),a=(s.getDay()+6)%7,i=[];for(let t=0;t<a;t++)i.push(null);for(let s=1;s<=o;s++)i.push({d:s,isToday:this.checkToday(t,e,s)});return i},checkToday(t,e,s){return t===this.today.getFullYear()&&e===this.today.getMonth()&&s===this.today.getDate()},prevMonth(){this.viewDate=new Date(this.viewDate.getFullYear(),this.viewDate.getMonth()-1,1)},nextMonth(){this.viewDate=new Date(this.viewDate.getFullYear(),this.viewDate.getMonth()+1,1)}}}window.showToast=function(t,e,s="",o=5e3){const a=new CustomEvent("show-toast",{detail:{type:t,title:e,message:s,duration:o}});window.dispatchEvent(a)},window.addEventListener("show-toast",t=>{const e=document.querySelector('[x-data*="toastManager"]');e&&e.__x&&e.__x.$data.addToast(t.detail.type,t.detail.title,t.detail.message,t.detail.duration)});